import "./App.css";
import HelloWorld from "./components/HelloWorld";
import SayMyName from "./components/SayMyName";

function App() {
  const name = "Milton";

  function sum(a, b) {
    return a + b;
  }

  const url =
    "https://images.unsplash.com/photo-1518791841217-8f162f1e1131?fm=jpg&q=60&w=3000&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MTR8fGdhdG9zfGVufDB8fDB8fHww";

  return (
    <div className="App">
      <img src={url} width="300" height="200" alt="Minha Imagem" />
      <HelloWorld />
      <SayMyName nome={name} />
    </div>
  );
}

export default App;
